+        assert_eq!(bound.confidence, 1.0);
+    }
+
+    #[test]
+    fn hoeffding_bound_narrows_with_samples() {
+        let b1 = hoeffding_bound(0.5, 100, 1.0, 0.05);
+        let b2 = hoeffding_bound(0.5, 10000, 1.0, 0.05);
