+        let samples = vec![0.3, 0.35, 0.32, 0.31, 0.33, 0.34, 0.30, 0.36];
+        let bound = empirical_bernstein_bound(&samples, 0.05);
+        assert!(bound.lower >= 0.0);
+        assert!(bound.upper > bound.lower);
+        assert!((bound.confidence - 0.95).abs() < 1e-10);
